66	 * stream, validates against ground truth, writes output files.
67	 */
68	export async function runScenario(
69	  scenario: Scenario,
70	  opts: RunOptions = {},
71	): Promise<RunResult> {
72	  const spawnFn = opts.spawn ?? realSpawn;
73	  const outRoot = opts.outRoot ?? '.hook-gym/runs';
74	  const hostRepo = opts.hostRepo ?? getHostRepo();
75	  const model = opts.modelOverride ?? scenario.model;
76	  const log = opts.log ?? console.log;
77	  const debug = opts.debug ?? false;
78	
79	  const ts = timestamp();
80	  const outDir = resolve(outRoot, `${ts}-${scenario.name}`);
81	  mkdirSync(outDir, { recursive: true });
82	
83	  const rendered = renderPrompt(scenario.prompt, {
84	    timestamp: ts,
85	    host_repo: hostRepo,
86	  });
87	
88	  log(`[hook-gym] Running scenario: ${scenario.name} (model=${model}, timeout=${scenario.timeoutSeconds}s, budget=$${scenario.maxBudget.toFixed(2)})`);
89	
90	  const streamLines: string[] = [];
91	  const processor = createHookStreamProcessor();
92	  const startMs = Date.now();
93	
94	  const result = await new Promise<{ timedOut: boolean; exitCode: number }>((resolve) => {
95	    const args = [
96	      '-p', rendered,
97	      '--model', model,
98	      '--verbose',
99	      '--output-format', 'stream-json',
100	      '--include-hook-events',
101	      '--max-turns', '50',
102	      '--allowedTools', 'Bash,Read,Write,Edit,Glob,Grep',
103	    ];
104	
105	    const child: ChildProcess = spawnFn('claude', args, {
106	      stdio: ['pipe', 'pipe', 'pipe'],
107	      env: { ...process.env },
108	    } as SpawnOptions);
109	
110	    let timedOut = false;
111	    const timer = setTimeout(() => {
112	      timedOut = true;
113	      log(`[hook-gym] Timeout (${scenario.timeoutSeconds}s) — killing subprocess.`);
114	      child.kill('SIGTERM');
115	      setTimeout(() => { if (!child.killed) child.kill('SIGKILL'); }, 5000);
116	    }, scenario.timeoutSeconds * 1000);
117	
118	    let stdoutBuf = '';
119	    child.stdout?.on('data', (chunk: Buffer) => {
120	      stdoutBuf += chunk.toString();
121	      let newlineIdx: number;
122	      while ((newlineIdx = stdoutBuf.indexOf('\n')) !== -1) {
123	        const line = stdoutBuf.slice(0, newlineIdx).trim();
124	        stdoutBuf = stdoutBuf.slice(newlineIdx + 1);
125	        if (!line) continue;
126	        streamLines.push(line);
127	        try {
128	          const msg = JSON.parse(line);
129	          const wasHook = processor.process(msg);
130	          if (wasHook && debug) {
131	            process.stderr.write(`[hook-event] ${line}\n`);
132	          }
133	        } catch {
134	          // Non-JSON line (e.g. stderr mixed in) — skip.
135	        }
136	      }
137	    });
138	
139	    child.stderr?.on('data', (chunk: Buffer) => {
140	      if (debug) process.stderr.write(chunk);
141	    });
142	
143	    child.on('close', (code) => {
144	      clearTimeout(timer);
145	      resolve({ timedOut, exitCode: code ?? 1 });
146	    });
147	
148	    child.on('error', (err) => {
149	      clearTimeout(timer);
150	      log(`[hook-gym] Spawn error: ${err.message}`);
151	      resolve({ timedOut, exitCode: 1 });
152	    });
153	  });
154	
155	  const durationMs = Date.now() - startMs;
156	  const timeline = processor.getTimeline();
157	
158	  log(`[hook-gym] Finished in ${(durationMs / 1000).toFixed(1)}s — ${timeline.events.length} hook events captured.`);
159	
160	  // Validate against ground truth
161	  const validation = validateAgainstScenario(timeline, scenario);
162	
163	  // Budget check (advisory)
164	  const budgetExceeded = false; // TODO: parse cost from stream when Claude CLI exposes it
165	
166	  // Write output files
167	  writeFileSync(join(outDir, 'stream.jsonl'), streamLines.join('\n') + '\n');
168	  writeFileSync(join(outDir, 'timeline.md'), formatTimeline(timeline));
169	  writeFileSync(join(outDir, 'result.json'), JSON.stringify({
170	    scenario: scenario.name,
171	    model,
172	    durationMs,
173	    timedOut: result.timedOut,
174	    budgetExceeded,
175	    exitCode: result.exitCode,
176	    hookEventCount: timeline.events.length,
177	    validation: {
178	      passed: validation.passed,
179	      hookMatches: validation.hookResults.length,
180	      gateMatches: validation.gateResults.length,
181	    },
182	    timeline,
183	  }, null, 2) + '\n');
184	
185	  log(`[hook-gym] Output written to ${outDir}`);
186	
187	  // Self-check: re-validate from the just-written fixture
188	  let selfCheckPassed = false;
189	  try {
190	    const replayReport = validateFixtureFile(join(outDir, 'stream.jsonl'), scenario);
191	    selfCheckPassed = replayReport.passed === validation.passed;
192	    if (!selfCheckPassed) {
193	      log(`[hook-gym] ⚠ Self-check MISMATCH: live=${validation.passed}, replay=${replayReport.passed}`);
194	    } else {
195	      log(`[hook-gym] Self-check: fixture replay matches live verdict (${validation.passed ? 'PASS' : 'FAIL'}).`);
196	    }
197	  } catch (err) {
198	    log(`[hook-gym] Self-check failed to run: ${err instanceof Error ? err.message : err}`);
199	  }
200	
201	  const passed = validation.passed && !result.timedOut && !budgetExceeded && selfCheckPassed;
202	
203	  // Print validation report
204	  log('');
205	  log(formatValidationReport(validation));
206	  log(summarizeTimeline(scenario.name, timeline));
207	
208	  if (result.timedOut) log(`[hook-gym] ❌ TIMEOUT after ${scenario.timeoutSeconds}s`);
209	  if (budgetExceeded) log(`[hook-gym] ❌ BUDGET EXCEEDED ($${scenario.maxBudget.toFixed(2)})`);
210	  if (!selfCheckPassed) log(`[hook-gym] ❌ SELF-CHECK FAILED (fixture replay disagrees with live verdict)`);
211	
212	  return {
213	    scenario: scenario.name,
214	    passed,
215	    timeline,
216	    validation,
217	    selfCheckPassed,
218	    timedOut: result.timedOut,
219	    budgetExceeded,
220	    durationMs,
221	    outDir,
222	    streamLines,
223	  };
224	}
