232	): Promise<{ results: RunResult[]; allPassed: boolean }> {
233	  const log = opts.log ?? console.log;
234	  const results: RunResult[] = [];
235	
236	  log(`[hook-gym] Running ${scenarios.length} scenarios...\n`);
237	
238	  for (const scenario of scenarios) {
239	    const result = await runScenario(scenario, opts);
240	    results.push(result);
241	    log('');
242	  }
243	
244	  // Summary table
245	  log('=== Hook Gym Summary ===\n');
246	  const maxName = Math.max(...results.map((r) => r.scenario.length));
247	  for (const r of results) {
248	    const status = r.passed ? '✅ PASS' : '❌ FAIL';
249	    const events = `${r.timeline.events.length} events`;
250	    const dur = `${(r.durationMs / 1000).toFixed(1)}s`;
251	    const flags = [
252	      r.timedOut ? 'TIMEOUT' : '',
253	      r.budgetExceeded ? 'BUDGET' : '',
254	      !r.selfCheckPassed ? 'SELF-CHECK' : '',
255	    ].filter(Boolean).join(', ');
256	    const flagStr = flags ? ` (${flags})` : '';
257	    log(`  ${r.scenario.padEnd(maxName)}  ${status}  ${events}  ${dur}${flagStr}`);
258	  }
259	
260	  const allPassed = results.every((r) => r.passed);
261	  const passCount = results.filter((r) => r.passed).length;
262	  log(`\n${passCount}/${results.length} scenarios passed.`);
263	
264	  return { results, allPassed };
