76	    console.error(`Available: ${SCENARIOS.map((s) => s.name).join(', ')}`);
77	    process.exit(1);
78	  }
79	
80	  const hostRepo = getHostRepo();
81	  const timestamp = new Date().toISOString().replace(/[-:T]/g, '').slice(0, 14);
82	
83	  const rendered = renderPrompt(scenario.prompt, {
84	    timestamp,
85	    host_repo: hostRepo,
