287	+/**
288	+ * hook-gym-format.ts — Human-readable timeline rendering for captured hook runs.
289	+ *
290	+ * Consumes a HookTimeline (from hook-gym-stream's processor) and produces the
291	+ * Markdown block shape described in docs/hook-gym-spec.md. Used by cmdRun to
292	+ * write `timeline.md` into each run's output directory and by cmdRunAll's
293	+ * summary table.
294	+ *
295	+ * Pure function — no I/O, no clock. Deterministic output for a given input.
296	+ */
297	+
298	+import type { HookTimeline, ParsedHookEvent } from './hook-gym-schema.js';
299	+
300	+/**
301	+ * Format a HookTimeline as a Markdown block. Structure:
302	+ *
303	+ *   # Hook Timeline — <n> events · <ms>ms
304	+ *
305	+ *   | t (ms) | event          | hook                  | decision    | dur (ms) | reason    |
306	+ *   |-------:|----------------|-----------------------|-------------|---------:|-----------|
307	+ *   | 0      | SessionStart   | SessionStart:startup  | none        | 5        | —         |
308	+ *   | ...
309	+ *
310	+ *   ## Gates
311	+ *   - needs_review: activated @123ms, cleared @4567ms
312	+ *   - needs_pr_kaizen: activated @2100ms (still active at run end)
313	+ *
314	+ * Gate ordering is deterministic (alphabetical by gate name). Events keep their
315	+ * input order (already sorted by timestamp by createHookStreamProcessor).
316	+ */
317	+export function formatTimeline(timeline: HookTimeline): string {
318	+  const events = timeline.events;
319	+  const endMs = events.reduce((m, e) => Math.max(m, e.timestamp), 0);
320	+
321	+  const out: string[] = [];
322	+  out.push(`# Hook Timeline — ${events.length} event${events.length === 1 ? '' : 's'} · ${endMs}ms`);
323	+  out.push('');
324	+
325	+  if (events.length === 0) {
326	+    out.push('_No hook events captured._');
327	+  } else {
328	+    const rows = events.map(renderEventRow);
329	+    out.push('| t (ms) | event | hook | decision | dur (ms) | reason |');
330	+    out.push('|-------:|-------|------|----------|---------:|--------|');
331	+    for (const row of rows) out.push(row);
332	+  }
333	+
334	+  out.push('');
335	+  out.push('## Gates');
336	+  out.push('');
337	+
338	+  const gateNames = new Set<string>([
339	+    ...Object.keys(timeline.gatesActivated),
340	+    ...Object.keys(timeline.gatesCleared),
341	+  ]);
342	+  if (gateNames.size === 0) {
343	+    out.push('_No gates observed._');
344	+  } else {
345	+    const sorted = [...gateNames].sort();
346	+    for (const name of sorted) {
347	+      out.push(`- ${formatGateLine(name, timeline)}`);
348	+    }
349	+  }
350	+
351	+  return out.join('\n') + '\n';
352	+}
353	+
354	+function renderEventRow(e: ParsedHookEvent): string {
355	+  const decision = e.decision ?? 'none';
356	+  const reason = e.reason ? truncate(e.reason, 60) : '—';
357	+  const hook = e.hookName || e.eventType;
358	+  return `| ${e.timestamp} | ${e.eventType} | ${escape(hook)} | ${decision} | ${e.durationMs} | ${escape(reason)} |`;
359	+}
360	+
361	+function formatGateLine(name: string, t: HookTimeline): string {
362	+  const activated = t.gatesActivated[name];
363	+  const cleared = t.gatesCleared[name];
364	+  if (activated != null && cleared != null) {
365	+    return `**${name}**: activated @${activated}ms, cleared @${cleared}ms`;
366	+  }
367	+  if (activated != null) {
368	+    return `**${name}**: activated @${activated}ms (still active at run end)`;
369	+  }
370	+  if (cleared != null) {
371	+    // clear without activation — happens when a run starts with a gate already
372	+    // set from a prior session
373	+    return `**${name}**: cleared @${cleared}ms (no activation observed this run)`;
374	+  }
375	+  return `**${name}**: (unknown)`;
376	+}
377	+
378	+function escape(s: string): string {
379	+  // Escape pipe characters so we don't corrupt the table.
380	+  return s.replace(/\|/g, '\\|');
381	+}
382	+
383	+function truncate(s: string, max: number): string {
384	+  if (s.length <= max) return s;
385	+  return s.slice(0, max - 1) + '…';
386	+}
387	+
388	+/**
389	+ * Produce a one-line summary for use in run-all summary tables:
390	+ *
391	+ *   "probe-hooks: 12 events · 2 gates · 4532ms"
392	+ */
393	+export function summarizeTimeline(name: string, timeline: HookTimeline): string {
394	+  const gates = new Set<string>([
395	+    ...Object.keys(timeline.gatesActivated),
396	+    ...Object.keys(timeline.gatesCleared),
397	+  ]).size;
398	+  const endMs = timeline.events.reduce((m, e) => Math.max(m, e.timestamp), 0);
399	+  return `${name}: ${timeline.events.length} events · ${gates} gates · ${endMs}ms`;
400	+}
